array_map(
			function( $tax ) use ( $operator ) {
				return array(
					'taxonomy' => $tax['taxonomy'],
					'field'    => 'term_id',
					'terms'    => $tax['terms'],
					'operator' => $operator,
					'include_children' => isset( $tax['includeChildren'] ) ? $tax['includeChildren'] : true,
				);
			},
			$raw_tax_query
		)

array_map(
			function( $user ) {
				// Always remove critical security fields.
				unset( $user->data->user_pass );
				unset( $user->data->user_activation_key );

				if ( ! current_user_can( 'manage_options' ) ) {
					// Remove sensitive values for non-admin users.
					unset( $user->data->user_login );
					unset( $user->data->user_email );

					// Remove capability data to prevent role enumeration.
					unset( $user->caps );
					unset( $user->allcaps );
				}

				return $user;
			},
			$query->get_results()
		)

array_map(
			function( $post ) {
				$requires_password = ! empty( $post->post_password ) && post_password_required( $post );
				$can_read_post     = current_user_can( 'read_post', $post->ID );
				$can_bypass_pw     = current_user_can( 'edit_post', $post->ID ) || get_current_user_id() === (int) $post->post_author;

				unset( $post->post_password );
				unset( $post->guid );
				unset( $post->post_content_filtered );

				if ( ! $can_read_post || ( $requires_password && ! $can_bypass_pw ) ) {
					unset( $post->post_content );
					unset( $post->post_excerpt );
				}

				return $post;
			},
			$query->posts
		)

array_map(
				function( $query ) {
					$query = array_filter(
						$query,
						function( $value ) {
							return ! empty( $value );
						}
					);
					return $query;
				},
				$args['date_query'] ?? []
			)

array_map(
			function( $tax ) use ( $operator ) {
				return array(
					'taxonomy' => $tax['taxonomy'],
					'field'    => 'term_id',
					'terms'    => $tax['terms'],
					'operator' => $operator,
					'include_children' => isset( $tax['includeChildren'] ) ? $tax['includeChildren'] : true,
				);
			},
			$raw_tax_query
		)

array_map(
			function ( $str ) {
				$result  = '';
				$escaped = false;
				$length  = strlen( $str );

				for ( $i = 0; $i < $length; $i++ ) {
					$char = $str[ $i ];

					if ( $escaped ) {
							$result .= $char;
							$escaped = false;
					} elseif ( '\\' === $char ) {
							$escaped = true;
					} elseif ( '"' !== $char && "'" !== $char ) {
							$result .= $char;
					}
				}

				return $result;
			},
			explode( ',', $options['replace'] )
		)

array_filter(
			get_user_meta( $user->ID ),
			function ( $key ) {
				$hidden  = is_protected_meta( $key, 'user' );
				$is_rest = $this->is_rest_field( $key );

				return ! $hidden && $is_rest;
			},
			ARRAY_FILTER_USE_KEY
		)

array_filter(
				get_post_meta( $id ),
				function ( $key ) {
					return ! is_protected_meta( $key, 'post' );
				},
				ARRAY_FILTER_USE_KEY
			)

array_map(
			function( $key ) use ( $keyMap ) {
				return isset( $keyMap[ $key ] ) ? $keyMap[ $key ] : $key;
			},
			array_keys( $arr )
		)

array_map(
		function( $attribute ) use ( $device, $settings ) {
			if ( isset( $settings['useInnerContainer'] ) && $settings['useInnerContainer'] ) {
				return false;
			}

			return generateblocks_get_array_attribute_value( $attribute . $device, $settings['spacing'] );
		},
		[
			'paddingTop',
			'paddingRight',
			'paddingBottom',
			'paddingLeft',
		]
	)

array_map(
				function( $value ) {
					return trim( implode( ' ', array_values( $value ) ) );
				},
				$border_values
			)

array_filter(
		$acf_options,
		function( $key ) {
			// Only allow string keys that don't start with underscore.
			return is_string( $key ) && strpos( $key, '_' ) !== 0;
		},
		ARRAY_FILTER_USE_KEY
	)

array_filter(
			$libraries,
			function( GenerateBlocks_Library_DTO $library ) use ( $enabled_only ) {
				if ( $enabled_only ) {
					return $library->is_enabled;
				}

				return true;
			}
		)

array_filter(
				$cached_data,
				function( $data ) use ( $query_args ) {
					foreach ( $data as $key => $value ) {
						if ( is_string( $value ) && stripos( $value, $query_args['search'] ) !== false ) {
							return true;
						}

						continue;
					}

					return false;
				}
			)

array_map(
			function( $library ) {
				if ( ! $library['isLocal'] && ! $library['isDefault'] ) {
					// Save all data if this is a remote library.
					return $library;
				}

				// Only save the ID and status for local and default libraries.
				// The rest of the data will be supplied via the PHP filter.
				return [
					'id' => $library['id'],
					'isEnabled' => $library['isEnabled'],
				];
			},
			$data
		)

